example.code:
pre_deploy_check() {
    local errors=0
    [[ ! -f "$ENV_FILE" ]] && echo "ERROR: $ENV_FILE not found" && ((errors++))

    local free_mb
    free_mb=$(df /srv --output=avail -BM | tail -1 | tr -d ' M')
    [[ "$free_mb" -lt 1024 ]] && echo "ERROR: Low disk: ${free_mb}MB" && ((errors++))

    systemctl --user status >/dev/null 2>&1 || { echo "ERROR: no systemd session"; ((errors++)); }

    [[ $errors -gt 0 ]] && { echo "Pre-deploy failed ($errors errors)"; exit 1; }
    echo "Pre-deploy checks passed"
}

restart_and_check() { local svc="$1" local port="${2:-}" systemctl --user restart "${svc}.service"
local waited=0 while [[ $waited -lt 30 ]]; do systemctl --user is-active "${svc}.service" &>/dev/null && break sleep 1; ((waited++)) done
systemctl --user is-active "${svc}.service" || { echo "ERROR: $svc failed to start" systemctl --user status "${svc}.service" --no-pager return 1 }
if [[ -n "$port" ]]; then curl -sf "http://127.0.0.1:${port}/health" >/dev/null || echo "WARN: health check failed" fi echo " $svc: OK" }
